SELECT a.name, a.icon, a.account_type, COALESCE(SUM( CASE WHEN a.account_type = 'EXPENSE' AND e.direction = 'DEBIT' THEN e.amount WHEN a.account_type = 'EXPENSE' AND e.direction = 'CREDIT' THEN -e.amount WHEN a.account_type = 'INCOME' AND e.direction = 'CREDIT' THEN e.amount WHEN a.account_type = 'INCOME' AND e.direction = 'DEBIT' THEN -e.amount ELSE 0 END ), 0) AS amount FROM fin_entries e JOIN fin_accounts a ON e.account_id = a.id JOIN fin_transactions t ON e.trans_id = t.id WHERE e.book_id = #{bookId} AND a.account_type = #{accountType}
AND t.trans_date >= #{startDate}
AND t.trans_date <= #{endDate}
GROUP BY a.id, a.name, a.icon, a.account_type HAVING COALESCE(SUM( CASE WHEN a.account_type = 'EXPENSE' AND e.direction = 'DEBIT' THEN e.amount WHEN a.account_type = 'EXPENSE' AND e.direction = 'CREDIT' THEN -e.amount WHEN a.account_type = 'INCOME' AND e.direction = 'CREDIT' THEN e.amount WHEN a.account_type = 'INCOME' AND e.direction = 'DEBIT' THEN -e.amount ELSE 0 END ), 0) > 0 ORDER BY amount DESC


SELECT id, type, category, icon, ABS(amount) AS amount, note
FROM classified
WHERE type = #{type}
  AND trans_date >= #{startDate}
  AND trans_date <= #{endDate}
ORDER BY ABS(amount) DESC, trans_date DESC, id DESC
LIMIT #{size}
